#include <stdio.h>
#include <stdlib.h>

typedef struct {int val; int idx;} Pair;
int cmpPair(const void *a, const void *b) {
    int va = ((Pair*)a)->val;
    int vb = ((Pair*)b)->val;
    return (va > vb) - (va < vb);
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        Pair *p = (Pair*)malloc(n * sizeof(Pair));
        for(int i=0;i<n;i++){
            scanf("%d", &p[i].val);
            p[i].idx = i;
        }
        qsort(p, n, sizeof(Pair), cmpPair);
        int ok = 1;
        for(int i=0;i<n;i++){
            if(abs(p[i].idx - i) > 1){ ok = 0; break; }
        }
        printf(ok?"YES\n":"NO\n");
        free(p);
    }
    return 0;
}

