const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let pos = 0;
const T = data[pos++];
let out = [];
for (let t = 0; t < T; t++) {
  const n = data[pos++];
  let pairs = new Array(n);
  for (let i = 0; i < n; i++) {
    pairs[i] = { val: data[pos++], idx: i };
  }
  pairs.sort((a, b) => a.val - b.val);
  let ok = true;
  for (let i = 0; i < n; i++) {
    if (Math.abs(pairs[i].idx - i) > 1) { ok = false; break; }
  }
  out.push(ok ? 'YES' : 'NO');
}
console.log(out.join('\n'));

